import http from "node:http";
/**
 * Spin up a localhost HTTP server for browser → CLI callbacks, used by the
 * login and label flows to receive a one-shot result from a chromeless
 * browser window. Built-in handling: CORS (including
 * `Access-Control-Allow-Private-Network` for Chrome's Private Network Access
 * preflight), OPTIONS preflight, a `/health` probe (so the web page can
 * verify loopback reachability before redirecting), 404 fallback, and
 * server-error rejection. Callers pass routes whose handlers call
 * `resolve(value)` with the parsed result.
 *
 * Does not throw on bind failure — returns a server with `available: false`
 * so callers can still use the exposed promise to drive a headless fallback
 * (e.g. stdin paste) through the same resolve/reject surface.
 */
export async function startLoopbackServer(port, routes) {
    let done = false;
    let resolveFn = () => { };
    let rejectFn = () => { };
    const promise = new Promise((resolve, reject) => {
        resolveFn = (value) => {
            if (done) {
                return;
            }
            done = true;
            resolve(value);
        };
        rejectFn = (err) => {
            if (done) {
                return;
            }
            done = true;
            reject(err);
        };
    });
    const server = http.createServer((req, res) => {
        res.setHeader("Access-Control-Allow-Origin", "*");
        res.setHeader("Access-Control-Allow-Methods", "GET, OPTIONS");
        // Chrome's Private Network Access requires this header on the preflight
        // response for HTTPS pages to fetch localhost. Without it, the browser
        // blocks the request even after the user approves the "allow this website
        // to access your loopback network" prompt, which silently kicks the flow
        // over to the headless paste fallback.
        // https://wicg.github.io/private-network-access/
        res.setHeader("Access-Control-Allow-Private-Network", "true");
        if (req.method === "OPTIONS") {
            res.writeHead(204);
            res.end();
            return;
        }
        const url = new URL(req.url ?? "/", `http://localhost:${port}`);
        if (url.pathname === "/health") {
            res.writeHead(200, { "Content-Type": "application/json" });
            res.end(JSON.stringify({ ok: true }));
            return;
        }
        const route = routes.find((r) => r.path === url.pathname);
        if (route) {
            try {
                route.handle(url.searchParams, res, resolveFn);
            }
            catch (err) {
                rejectFn(err);
            }
            return;
        }
        res.writeHead(404);
        res.end();
    });
    let bindError = null;
    try {
        await new Promise((resolve, reject) => {
            const onError = (err) => {
                server.removeListener("listening", onListening);
                reject(err);
            };
            const onListening = () => {
                server.removeListener("error", onError);
                resolve();
            };
            server.once("error", onError);
            server.once("listening", onListening);
            // Bind loopback-only: sandboxed runtimes (Codex, containers with
            // tightened netns) only permit 127.0.0.1; the browser handoff only
            // needs loopback anyway.
            server.listen(port, "127.0.0.1");
        });
    }
    catch (err) {
        bindError = err;
    }
    const available = bindError === null;
    if (available) {
        server.on("error", (err) => {
            rejectFn(new Error(`Loopback server error: ${err.message}`));
        });
    }
    else {
        // The channel is unusable but callers still have a handle to `promise`
        // and `reject`. Silently absorb any rejection so a `reject()` call from
        // the caller doesn't surface as an unhandled promise rejection.
        promise.catch(() => { });
    }
    return {
        promise,
        get done() {
            return done;
        },
        available,
        bindError,
        resolve: resolveFn,
        reject: rejectFn,
        close: () => {
            if (available) {
                server.close();
            }
        },
    };
}
